import{_ as a,o,c as t,ae as l}from"./chunks/framework.BEtfQoF7.js";const h=JSON.parse('{"title":"Week 14 · 2026년 3월 30일 – 4월 3일","description":"Computer use CLI 지원, /powerup 인터랙티브 레슨, 깜빡임 없는 렌더링 등 Claude Code v2.1.86~v2.1.91 신규 기능 요약","frontmatter":{"title":"Week 14 · 2026년 3월 30일 – 4월 3일","description":"Computer use CLI 지원, /powerup 인터랙티브 레슨, 깜빡임 없는 렌더링 등 Claude Code v2.1.86~v2.1.91 신규 기능 요약"},"headers":[],"relativePath":"whats-new/2026-w14.md","filePath":"whats-new/2026-w14.md","lastUpdated":null}'),i={name:"whats-new/2026-w14.md"};function d(r,e,c,s,u,n){return o(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="week-14-·-2026년-3월-30일-–-4월-3일" tabindex="-1">Week 14 · 2026년 3월 30일 – 4월 3일 <a class="header-anchor" href="#week-14-·-2026년-3월-30일-–-4월-3일" aria-label="Permalink to &quot;Week 14 · 2026년 3월 30일 – 4월 3일&quot;">​</a></h1><p>릴리스: v2.1.86 → v2.1.91, 5개 신규 기능</p><h2 id="기능-1-cli에서-computer-use-리서치-프리뷰" tabindex="-1">기능 1: CLI에서 Computer use (리서치 프리뷰) <a class="header-anchor" href="#기능-1-cli에서-computer-use-리서치-프리뷰" aria-label="Permalink to &quot;기능 1: CLI에서 Computer use (리서치 프리뷰)&quot;">​</a></h2><p>지난 주 Desktop 앱에 Computer use가 도입되었다면, 이번 주에는 CLI에서도 사용 가능. Claude가 네이티브 앱을 열고, UI를 클릭하고, 자신의 변경 사항을 테스트하고, 문제가 생기면 직접 수정 — 모두 터미널에서. 초기 단계이므로 불안정한 부분이 있을 수 있음.</p><h2 id="기능-2-powerup-v2-1-90" tabindex="-1">기능 2: /powerup (v2.1.90) <a class="header-anchor" href="#기능-2-powerup-v2-1-90" aria-label="Permalink to &quot;기능 2: /powerup (v2.1.90)&quot;">​</a></h2><p>터미널 내에서 애니메이션 데모를 통해 Claude Code 기능을 가르치는 인터랙티브 레슨.</p><h2 id="기능-3-깜빡임-없는-렌더링-v2-1-89" tabindex="-1">기능 3: 깜빡임 없는 렌더링 (v2.1.89) <a class="header-anchor" href="#기능-3-깜빡임-없는-렌더링-v2-1-89" aria-label="Permalink to &quot;기능 3: 깜빡임 없는 렌더링 (v2.1.89)&quot;">​</a></h2><p>가상화된 스크롤백을 갖춘 새로운 alt-screen 렌더러를 선택적으로 사용. <code>CLAUDE_CODE_NO_FLICKER=1</code>로 설정.</p><h2 id="기능-4-mcp-결과-크기-오버라이드-v2-1-91" tabindex="-1">기능 4: MCP 결과 크기 오버라이드 (v2.1.91) <a class="header-anchor" href="#기능-4-mcp-결과-크기-오버라이드-v2-1-91" aria-label="Permalink to &quot;기능 4: MCP 결과 크기 오버라이드 (v2.1.91)&quot;">​</a></h2><p>MCP 서버 작성자가 <code>tools/list</code>에 <code>&quot;anthropic/maxResultSizeChars&quot;</code>를 설정하여 특정 툴의 잘림 상한을 최대 50만 자까지 올릴 수 있음.</p><h2 id="기능-5-플러그인-실행-파일-path-추가-v2-1-91" tabindex="-1">기능 5: 플러그인 실행 파일 PATH 추가 (v2.1.91) <a class="header-anchor" href="#기능-5-플러그인-실행-파일-path-추가-v2-1-91" aria-label="Permalink to &quot;기능 5: 플러그인 실행 파일 PATH 추가 (v2.1.91)&quot;">​</a></h2><p>플러그인 루트의 <code>bin/</code> 디렉터리에 실행 파일을 넣으면 Claude Code가 Bash 툴의 PATH에 해당 디렉터리를 자동 추가.</p><h2 id="기타-개선-사항" tabindex="-1">기타 개선 사항 <a class="header-anchor" href="#기타-개선-사항" aria-label="Permalink to &quot;기타 개선 사항&quot;">​</a></h2><ul><li>Auto mode 후속 처리: 분류기 거부 시 PermissionDenied 훅 지원</li><li>PreToolUse 훅의 <code>permissionDecision</code>에 새로운 <code>&quot;defer&quot;</code> 값 추가</li><li><code>/buddy</code>: 코딩하는 모습을 지켜보는 작은 생명체 부화 (4월 1일)</li><li><code>disableSkillShellExecution</code> 설정 추가</li><li>Edit 툴이 <code>cat</code> 또는 <code>sed -n</code>으로 본 파일에도 동작</li><li>50K 이상의 훅 출력은 디스크에 저장</li><li>Thinking 요약 기본 해제</li><li>음성 모드: push-to-talk 수정자 조합 지원</li><li><code>claude-cli://</code> 딥 링크에서 여러 줄 프롬프트 지원</li></ul>',14)])])}const m=a(i,[["render",d]]);export{h as __pageData,m as default};
